#include <bits/stdc++.h>
using namespace std;
int main(){
    int x,y,z;
    cin>>x>>y>>z;
    int a[x][y];
    for(int i=0;i<x;i++){
        for(int j=0;j<y;j++){
            cin>>a[i][j];
        }
    }
    int ans=0;
    for(int i=0;i<x-2;i++){
        for(int j=0;j<y-2;j++){
            int b=0,s=100005,m=0;
            for(int k=i;k<i+3;k++){
                for(int l=j;l<j+3;l++){
                    b=max(a[k][l],b);
                    s=min(a[k][l],s);
                    m+=a[k][l];
                }
            }
            if(b-s<=z){
                ans=max(ans,m);
            }
        }
    }
    cout<<ans;
    return 0;
}
